const b = $input.first().json.body || $input.first().json;
const d = b.data || b;
const key = d.key || {};
const msg = d.message || {};
const text = msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || d.text || '';
const phone = (key.remoteJid || d.remoteJid || '').split('@')[0];
const isGroup = (key.remoteJid||'').includes('@g.us');
return [{ json: {
  phone,
  name: d.pushName || '',
  text: (text||'').trim(),
  from_me: key.fromMe === true,
  message_id: key.id || '',
  is_group: isGroup
}}];

