// Recebe a saida do Agente e prepara mensagens humanizadas
const out = ($json.output || '').toString();
// Remove o bloco oculto de controle ###META###{...}
let limpo = out.split('###META###')[0];
// Quebra em mensagens separadas usando o separador ||| definido no prompt
let partes = limpo.split('|||').map(s => s.trim()).filter(s => s.length > 0);
// Seguranca: se nao houver separador, manda como 1 mensagem
if (partes.length === 0) { partes = [limpo.trim()].filter(Boolean); }
const phone = $('Dados').item.json.phone;
return partes.map((text, i) => {
  // tempo de 'digitando' proporcional ao tamanho do texto
  const digitando = Math.min(6000, Math.max(1200, text.length * 45));
  return { json: { phone, text, digitando, idx: i, total: partes.length } };
});
